def rotate_rings(matrix, rotations):
    if not matrix or not matrix[0]:
        return matrix

    n = len(matrix)
    m = len(matrix[0])

    result = [row[:] for row in matrix]

    num_rings = (min(n, m) + 1) // 2

    for ring in range(min(num_rings, len(rotations))):
        top, bottom, left, right = ring, n - 1 - ring, ring, m - 1 - ring

        if top > bottom or left > right:
            break

        positions = []

        if top == bottom:
            for c in range(left, right + 1):
                positions.append((top, c))
        elif left == right:
            for r in range(top, bottom + 1):
                positions.append((r, left))
        else:
            for c in range(left, right):
                positions.append((top, c))
            for r in range(top, bottom):
                positions.append((r, right))
            for c in range(right, left, -1):
                positions.append((bottom, c))
            for r in range(bottom, top, -1):
                positions.append((r, left))

        values = [matrix[r][c] for r, c in positions]
        k = rotations[ring] % len(values)

        rotated_vals = [values[(i - k) % len(values)] for i in range(len(values))]

        for idx, (r, c) in enumerate(positions):
            result[r][c] = rotated_vals[idx]

    return result
